import{_ as e,o as a,c as d,a0 as r}from"./chunks/framework.AQcSKqPn.js";const _=JSON.parse('{"title":"大数据封神！无职S3回归直接封神","description":"","frontmatter":{"type":"social_post","platform":"xiaohongshu","date":"2026-07-11T00:00:00.000Z","anime":"Mushoku Tensei III: Isekai Ittara Honki Dasu","tone":"normal"},"headers":[],"relativePath":"social_posts/2026-07-11.md","filePath":"social_posts/2026-07-11.md","lastUpdated":1784513544000}'),o={name:"social_posts/2026-07-11.md"};function s(p,t,i,n,l,h){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="大数据封神-无职s3回归直接封神" tabindex="-1">大数据封神！无职S3回归直接封神 <a class="header-anchor" href="#大数据封神-无职s3回归直接封神" aria-label="Permalink to &quot;大数据封神！无职S3回归直接封神&quot;">​</a></h1><ul><li><strong>发布日期</strong>: 2026年07月12日 姐妹们看了无职S3第一集没！！😭 Studio Bind的作画真的杀疯了，鲁迪重回学院那段运镜我直接一帧帧截图当壁纸。但最让我尖叫的是——菲兹！！短发希露菲出来的时候我整个人在屏幕前化身尖叫鸡🐔</li></ul><p>🎓 学院篇正式启动 第一集就把氛围拉满，鲁迪穿越后第一次以「本気だす」的姿态踏进ラノア魔法学院的大门。不再是那个只会缩在角落的肥宅尼特了，是真的在认真生活、认真交朋友、认真变强啊谁懂！！这成长弧线我吹爆🔥</p><p>👀 菲兹的身份秘密 看过原作的都知道菲兹就是我们的白毛老婆希露菲！但纯动画党可能还在懵圈状态——这个金发侍卫怎么对鲁迪这么温柔？拜托那可是你上辈子就娶回家的人啊！😭 短发希露菲的颜值我真的好了，又飒又温柔这是什么神仙造型，制作组加鸡腿🍗</p><p>✨ 作画和演出 这一季的经费肉眼可见的充足！从鲁迪施法的粒子特效到学院建筑的透视构图，每一帧都在燃烧经费。Studio Bind你是我的神🙏 ED的镜头语言也绝了，菲兹的背影和鲁迪的视线交错，谁看了不说一句纯爱战士应声倒地</p><p>💘 为什么必须追 无职转生从来不是在讲「异世界装逼打脸」。它讲的是一个彻彻底底的废柴，如何抓住第二次人生拼了命地活下去。而S3的学院篇，正是他第一次真正拥有「正常生活」的开始——有朋友、有目标、有暗恋的人。这谁顶得住啊！！</p><p>🔥 本周最炸场面 鲁迪在入学测试上不小心露了一手，全校震惊，而菲兹在旁边默默露出「不愧是我选中的男人」的表情。这个细节我反复看了5遍！！有没有人跟我一样磕到了！！</p><p>快来评论区告诉我——你觉得菲兹这季会摘下面罩跟鲁迪相认吗？是期中就摊牌还是等到季末憋大招？开盘了开盘了！！🫘</p><h2 id="图片" tabindex="-1">图片 <a class="header-anchor" href="#图片" aria-label="Permalink to &quot;图片&quot;">​</a></h2><table tabindex="0"><thead><tr><th>图片</th><th>文件</th><th>文件</th></tr></thead><tbody><tr><td>封面</td><td>p1.png</td><td>Sylphiette (Fitz) with cover text</td></tr><tr><td>配图1</td><td>p2.png</td><td>Rudeus entering Ranoa University</td></tr><tr><td>配图2</td><td>p3.png</td><td>Fitz/Sylphiette close-up</td></tr><tr><td>配图3</td><td>p4.png</td><td>Rudeus casting spell</td></tr><tr><td>配图4</td><td>p5.png</td><td>Sylphiette portrait</td></tr><tr><td>配图5</td><td>p6.png</td><td>Group scene in classroom</td></tr></tbody></table>',10)])])}const u=e(o,[["render",s]]);export{_ as __pageData,u as default};
